import React, { useState } from 'react';
import ProjectCard from './ProjectCard';
import ProjectDetail from './ProjectDetail';
import './ProjectList.css';

function ProjectList({ projects, loading, onUpdate }) {
  const [selectedProject, setSelectedProject] = useState(null);
  const [selectedIndex, setSelectedIndex] = useState(null);

  if (loading) {
    return (
      <div className="project-list">
        <div className="loading-state">
          <div className="loading-spinner"></div>
          <p>Loading project briefs...</p>
        </div>
      </div>
    );
  }

  if (projects.length === 0) {
    return (
      <div className="project-list">
        <div className="empty-state">
          <div className="empty-icon">📭</div>
          <h3>No project briefs yet</h3>
          <p>Project briefs submitted from the website will appear here.</p>
        </div>
      </div>
    );
  }

  const handleSelectProject = (project, index) => {
    setSelectedProject(project);
    setSelectedIndex(index);
  };

  const handleCloseDetail = () => {
    setSelectedProject(null);
    setSelectedIndex(null);
    onUpdate();
  };

  const handleProjectUpdate = () => {
    onUpdate();
  };

  return (
    <div className="project-list">
      <div className="project-list-header">
        <span className="project-count-label">
          {projects.length} project{projects.length !== 1 ? 's' : ''}
        </span>
      </div>

      <div className="project-grid">
        {projects.map((project, index) => (
          <ProjectCard
            key={index}
            project={project}
            index={index}
            onSelect={handleSelectProject}
          />
        ))}
      </div>

      {selectedProject && (
        <ProjectDetail
          project={selectedProject}
          index={selectedIndex}
          onClose={handleCloseDetail}
          onUpdate={handleProjectUpdate}
        />
      )}
    </div>
  );
}

export default ProjectList;