// src/components/Charts.js
import React from 'react';
import { Chart as ChartJS, ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title } from 'chart.js';
import { Pie, Bar } from 'react-chartjs-2';
import { formatStatus, getStatusColor } from '../utils/localStorage';
import './Charts.css';

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

function Charts({ briefs }) {
    // Calculate data for charts
    const getChartData = () => {
        // Status distribution
        const statusCounts = {};
        briefs.forEach(b => {
            const status = b.status || 'new';
            statusCounts[status] = (statusCounts[status] || 0) + 1;
        });

        const statusLabels = Object.keys(statusCounts);
        const statusValues = Object.values(statusCounts);
        const statusColors = statusLabels.map(s => getStatusColor(s));

        // Deposit status
        const depositPaid = briefs.filter(b => b.depositPaid === true).length;
        const depositPending = briefs.filter(b => b.depositPaid !== true).length;

        // Project type distribution
        const typeCounts = {};
        briefs.forEach(b => {
            const type = b.projectType || 'other';
            typeCounts[type] = (typeCounts[type] || 0) + 1;
        });

        const typeLabels = Object.keys(typeCounts);
        const typeValues = Object.values(typeCounts);
        const typeColors = ['#0066cc', '#009688', '#d4a000', '#5e3c9e', '#c62828', '#0d7c3f', '#64748b'];

        return {
            status: {
                labels: statusLabels.map(formatStatus),
                datasets: [{
                    data: statusValues,
                    backgroundColor: statusColors,
                    borderColor: statusColors.map(c => c),
                    borderWidth: 1,
                }]
            },
            deposit: {
                labels: ['Deposit Paid', 'Deposit Pending'],
                datasets: [{
                    data: [depositPaid, depositPending],
                    backgroundColor: ['#0d7c3f', '#c62828'],
                    borderColor: ['#0d7c3f', '#c62828'],
                    borderWidth: 1,
                }]
            },
            type: {
                labels: typeLabels.map(formatProjectType),
                datasets: [{
                    data: typeValues,
                    backgroundColor: typeColors.slice(0, typeLabels.length),
                    borderColor: typeColors.slice(0, typeLabels.length),
                    borderWidth: 1,
                }]
            }
        };
    };

    const formatProjectType = (type) => {
        const types = {
            'full-build': 'Full Build',
            'revamp': 'Revamp / Redesign',
            'landing-page': 'Landing Page',
            'ecommerce': 'E-commerce Store',
            'dashboard': 'Dashboard / Analytics',
            'custom-system': 'Custom Business System',
            'other': 'Other'
        };
        return types[type] || type || 'Not specified';
    };

    const chartData = getChartData();
    const hasData = briefs.length > 0;

    if (!hasData) {
        return (
            <div className="charts-empty">
                <p>No data to display charts yet. Submit some projects!</p>
            </div>
        );
    }

    const options = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                position: 'bottom',
                labels: {
                    padding: 20,
                    usePointStyle: true,
                    pointStyle: 'circle',
                    font: {
                        size: 11
                    }
                }
            }
        }
    };

    return (
        <div className="charts-container">
            <div className="chart-card">
                <h3>Project Status</h3>
                <div className="chart-wrapper">
                    <Pie data={chartData.status} options={options} />
                </div>
            </div>

            <div className="chart-card">
                <h3>Deposit Status</h3>
                <div className="chart-wrapper">
                    <Pie data={chartData.deposit} options={options} />
                </div>
            </div>

            <div className="chart-card">
                <h3>Project Types</h3>
                <div className="chart-wrapper">
                    <Pie data={chartData.type} options={options} />
                </div>
            </div>
        </div>
    );
}

export default Charts;