// src/components/Dashboard.js
import React, { useState, useEffect } from 'react';
import { getProjectBriefs, getProjectStats } from '../utils/localStorage';
import StatsCards from './StatsCards';
import SearchFilter from './SearchFilter';
import ProjectList from './ProjectList';
import Charts from './Charts';
import './Dashboard.css';

function Dashboard() {
    const [projects, setProjects] = useState([]);
    const [filteredProjects, setFilteredProjects] = useState([]);
    const [stats, setStats] = useState({ 
        total: 0, 
        byType: {}, 
        byStatus: {}, 
        byDeposit: { paid: 0, pending: 0 },
        recent: 0,
        inProgress: 0,
        withEstimates: 0
    });
    const [searchTerm, setSearchTerm] = useState('');
    const [filterType, setFilterType] = useState('all');
    const [filterStatus, setFilterStatus] = useState('all');
    const [loading, setLoading] = useState(true);
    const [lastUpdated, setLastUpdated] = useState(null);

    // Load data from localStorage
    const loadData = () => {
        setLoading(true);
        const briefs = getProjectBriefs();
        setProjects(briefs);
        setFilteredProjects(briefs);
        setStats(getProjectStats());
        setLastUpdated(new Date().toLocaleString());
        setLoading(false);
    };

    // Refresh data periodically
    useEffect(() => {
        loadData();
        
        // Refresh every 30 seconds
        const interval = setInterval(loadData, 30000);
        
        // Listen for storage changes from other tabs
        const handleStorageChange = (e) => {
            if (e.key === 'cascade_project_briefs') {
                loadData();
            }
        };
        window.addEventListener('storage', handleStorageChange);
        
        return () => {
            clearInterval(interval);
            window.removeEventListener('storage', handleStorageChange);
        };
    }, []);

    // Apply filters
    useEffect(() => {
        let filtered = [...projects];

        // Search filter
        if (searchTerm.trim()) {
            const term = searchTerm.toLowerCase().trim();
            filtered = filtered.filter(p => 
                p.name?.toLowerCase().includes(term) ||
                p.email?.toLowerCase().includes(term) ||
                p.projectName?.toLowerCase().includes(term) ||
                p.description?.toLowerCase().includes(term)
            );
        }

        // Type filter
        if (filterType !== 'all') {
            filtered = filtered.filter(p => p.projectType === filterType);
        }

        // Status filter
        if (filterStatus !== 'all') {
            filtered = filtered.filter(p => p.status === filterStatus);
        }

        setFilteredProjects(filtered);
    }, [projects, searchTerm, filterType, filterStatus]);

    const handleProjectUpdate = () => {
        loadData();
    };

    return (
        <div className="dashboard">
            <header className="dashboard-header">
                <div className="header-content">
                    <div className="header-left">
                        <h1>
                            <span className="header-icon">📋</span>
                            Cascade Creations
                            <span className="header-sub">Project Briefs</span>
                        </h1>
                    </div>
                    <div className="header-right">
                        <button className="btn-refresh" onClick={loadData}>
                            <span className="refresh-icon">⟳</span> Refresh
                        </button>
                        <span className="project-count">
                            {projects.length} project{projects.length !== 1 ? 's' : ''}
                        </span>
                        {lastUpdated && (
                            <span className="last-updated">
                                Updated: {lastUpdated}
                            </span>
                        )}
                    </div>
                </div>
            </header>

            <main className="dashboard-main">
                <StatsCards stats={stats} />

                <Charts briefs={projects} />

                <SearchFilter
                    searchTerm={searchTerm}
                    setSearchTerm={setSearchTerm}
                    filterType={filterType}
                    setFilterType={setFilterType}
                    filterStatus={filterStatus}
                    setFilterStatus={setFilterStatus}
                />

                <ProjectList
                    projects={filteredProjects}
                    loading={loading}
                    onUpdate={handleProjectUpdate}
                />
            </main>
        </div>
    );
}

export default Dashboard;